def solve(intervals):
    intervals.sort(key=lambda x: (x[1], -x[0]))
    ans = 0
    p1, p2 = -1, -1
    for s, e in intervals:
        if s > p2:
            ans += 2
            p1, p2 = e - 1, e
        elif s > p1:
            ans += 1
            p1, p2 = p2, e
    return str(ans)

